	visited := make(map[string]bool)
	stack := make(map[string]bool)

	var visit func(string) bool
	visit = func(id string) bool {
		visited[id] = true
		stack[id] = true

		for _, dep := range deps[id] {
			if !visited[dep] {
				if visit(dep) {
					return true
				}
			} else if stack[dep] {
				return true
			}
		}

		stack[id] = false
		return false
	}

	return visit(startID)
