func normalizeChildIDs(children []string) []string {
	var out []string
	seen := map[string]bool{}
	for _, raw := range children {
		for _, part := range strings.Split(raw, ",") {
			child := strings.TrimSpace(part)
			if child == "" || seen[child] {
				continue
			}
			seen[child] = true
			out = append(out, child)
		}
	}
